    @Test("ChannelBuffers is constructible with empty arrays")
    func channelBuffers_emptyArraysAreValid() { ... }

    @Test("ChannelBuffers systemSamples is interleaved stereo — not folded")
    func channelBuffers_systemSamples_isFullStereo() {
        // Verify that ChannelBuffers carries raw stereo (even frame count)
        // to document the contract
    }
