import AVFoundation
import Foundation
import os

/// Mixes microphone and system audio into a stereo recording.
///
/// `StereoMixer` takes mono microphone audio and stereo system audio, mixing
/// them into a natural-sounding stereo output where:
/// - **Left**  = mic + system left
/// - **Right** = mic + system right
///
/// This preserves the stereo image of the system audio while placing the
/// microphone in the center of the stereo field, producing a recording
/// suitable for both playback and downstream AI processing.
///
/// If the sources have different sample rates, the mixer resamples to the
/// target rate (default 48kHz).
public struct StereoMixer: Sendable {
    /// The target sample rate for the mixed output.
    public let targetSampleRate: Double

    private static let logger = Logger(
        subsystem: "com.audiocapturekit",
        category: "StereoMixer"
    )

    /// Creates a new stereo mixer.
    /// - Parameter targetSampleRate: The desired output sample rate in Hz. Default is 48000.
    public init(targetSampleRate: Double = 48000) {
        self.targetSampleRate = targetSampleRate
    }

    /// Mixes mono microphone audio with interleaved stereo system audio.
    ///
    /// The mic signal is added equally to both channels, preserving the stereo
    /// image of the system audio. If one source is shorter, it is zero-padded.
    ///
    /// - Parameters:
    ///   - mic: Mono microphone samples.
    ///   - system: Interleaved stereo system audio [L0, R0, L1, R1, ...].
    /// - Returns: Interleaved stereo samples [L0, R0, L1, R1, ...].
    public func mixMicWithStereoSystem(mic: [Float], system: [Float]) -> [Float] {
        let micFrames = mic.count
        let systemFrames = system.count / 2
        let frameCount = max(micFrames, systemFrames)
        guard frameCount > 0 else { return [] }

        var stereo = [Float](repeating: 0, count: frameCount * 2)
        for i in 0 ..< frameCount {
            let micSample = i < micFrames ? mic[i] : 0
            let sysL = (i * 2) < system.count ? system[i * 2] : 0
            let sysR = (i * 2 + 1) < system.count ? system[i * 2 + 1] : 0
            stereo[i * 2] = micSample + sysL
            stereo[i * 2 + 1] = micSample + sysR
        }
        return stereo
    }

    /// Interleaves two mono sample arrays into stereo.
    ///
    /// The left channel receives the first array and the right channel
    /// receives the second. If the arrays differ in length, the shorter
    /// one is zero-padded to match.
    ///
    /// - Parameters:
    ///   - leftSamples: Mono samples for the left channel.
    ///   - rightSamples: Mono samples for the right channel.
    /// - Returns: Interleaved stereo samples [L0, R0, L1, R1, ...].
    public func interleave(left leftSamples: [Float], right rightSamples: [Float]) -> [Float] {
        let frameCount = max(leftSamples.count, rightSamples.count)
        guard frameCount > 0 else { return [] }

        var stereo = [Float](repeating: 0, count: frameCount * 2)
        for i in 0 ..< frameCount {
            stereo[i * 2] = i < leftSamples.count ? leftSamples[i] : 0
            stereo[i * 2 + 1] = i < rightSamples.count ? rightSamples[i] : 0
        }
        return stereo
    }

    /// Converts interleaved Float32 stereo samples to 16-bit PCM data.
    ///
    /// Float samples are expected in the range [-1.0, 1.0] and are clamped
    /// before conversion to prevent overflow.
    ///
    /// - Parameter samples: Interleaved stereo Float32 samples.
    /// - Returns: Raw 16-bit little-endian PCM data.
    public func convertToInt16PCM(_ samples: [Float]) -> Data {
        var data = Data(capacity: samples.count * 2)
        for sample in samples {
            let clamped = max(-1.0, min(1.0, sample))
            var int16Value = Int16(clamped * Float(Int16.max))
            withUnsafeBytes(of: &int16Value) { data.append(contentsOf: $0) }
        }
        return data
    }

    /// Resamples a mono audio buffer using linear interpolation.
    ///
    /// - Parameters:
    ///   - samples: The input mono samples at the source sample rate.
    ///   - sourceSampleRate: The sample rate of the input data.
    /// - Returns: Resampled samples at the target sample rate.
    public func resample(_ samples: [Float], from sourceSampleRate: Double) -> [Float] {
        guard sourceSampleRate != targetSampleRate, !samples.isEmpty else {
            return samples
        }

        let ratio = targetSampleRate / sourceSampleRate
        let outputCount = Int(Double(samples.count) * ratio)
        guard outputCount > 0 else { return [] }

        var output = [Float](repeating: 0, count: outputCount)
        for i in 0 ..< outputCount {
            let sourceIndex = Double(i) / ratio
            let index = Int(sourceIndex)
            let fraction = Float(sourceIndex - Double(index))

            if index + 1 < samples.count {
                output[i] = samples[index] * (1 - fraction) + samples[index + 1] * fraction
            } else if index < samples.count {
                output[i] = samples[index]
            }
        }

        return output
    }

    /// Resamples interleaved stereo audio using linear interpolation.
    ///
    /// Each channel is resampled independently to preserve the stereo image.
    ///
    /// - Parameters:
    ///   - samples: Interleaved stereo samples [L0, R0, L1, R1, ...].
    ///   - sourceSampleRate: The sample rate of the input data.
    /// - Returns: Resampled interleaved stereo samples at the target sample rate.
    public func resampleStereo(_ samples: [Float], from sourceSampleRate: Double) -> [Float] {
        guard sourceSampleRate != targetSampleRate, !samples.isEmpty else {
            return samples
        }

        let frameCount = samples.count / 2
        let ratio = targetSampleRate / sourceSampleRate
        let outputFrames = Int(Double(frameCount) * ratio)
        guard outputFrames > 0 else { return [] }

        var output = [Float](repeating: 0, count: outputFrames * 2)
        for i in 0 ..< outputFrames {
            let sourceIndex = Double(i) / ratio
            let index = Int(sourceIndex)
            let fraction = Float(sourceIndex - Double(index))

            for ch in 0 ..< 2 {
                if index + 1 < frameCount {
                    output[i * 2 + ch] = samples[index * 2 + ch] * (1 - fraction)
                        + samples[(index + 1) * 2 + ch] * fraction
                } else if index < frameCount {
                    output[i * 2 + ch] = samples[index * 2 + ch]
                }
            }
        }

        return output
    }
}

import Foundation

/// Represents the type of an audio track.
public enum AudioTrackType: String, Sendable, Codable {
    /// Microphone input (what the user speaks).
    case mic

    /// System audio (what the user hears).
    case system
}

/// Represents the stereo channel assignment for an audio track.
public enum AudioChannel: String, Sendable, Codable {
    /// Left stereo channel.
    case left = "L"

    /// Right stereo channel.
    case right = "R"

    /// Center (mixed into both channels).
    case center = "C"

    /// Full stereo (present in both channels).
    case stereo = "LR"
}

/// Describes an audio track within a recording.
public struct AudioTrack: Sendable, Codable, Equatable {
    /// The source type of this track.
    public let type: AudioTrackType

    /// The stereo channel this track is assigned to.
    public let channel: AudioChannel

    public init(type: AudioTrackType, channel: AudioChannel) {
        self.type = type
        self.channel = channel
    }
}

/// Describes the transport type of an audio device.
public enum AudioTransportType: String, Sendable, Equatable {
    case builtIn
    case bluetooth
    case bluetoothLE
    case usb
    case virtual
    case unknown
}

/// Describes an available audio source on the system.
public struct AudioSource: Sendable, Equatable, Identifiable {
    /// Unique identifier for this audio source.
    public let id: String

    /// Human-readable name of the audio source.
    public let name: String

    /// The type of audio this source provides.
    public let type: AudioTrackType

    /// Whether this is the default device for its type.
    public let isDefault: Bool

    /// The transport type of this audio device (e.g. built-in, Bluetooth).
    public let transportType: AudioTransportType?

    public init(
        id: String,
        name: String,
        type: AudioTrackType,
        isDefault: Bool,
        transportType: AudioTransportType? = nil
    ) {
        self.id = id
        self.name = name
        self.type = type
        self.isDefault = isDefault
        self.transportType = transportType
    }
}

/// Real-time audio level metering information.
public struct AudioLevels: Sendable, Equatable {
    /// Current RMS level of the microphone input (0.0 to 1.0).
    public let micLevel: Float

    /// Current RMS level of the system audio input (0.0 to 1.0).
    public let systemLevel: Float

    /// Peak level of the microphone input (0.0 to 1.0).
    public let peakMicLevel: Float

    /// Peak level of the system audio input (0.0 to 1.0).
    public let peakSystemLevel: Float

    public init(
        micLevel: Float = 0,
        systemLevel: Float = 0,
        peakMicLevel: Float = 0,
        peakSystemLevel: Float = 0
    ) {
        self.micLevel = micLevel
        self.systemLevel = systemLevel
        self.peakMicLevel = peakMicLevel
        self.peakSystemLevel = peakSystemLevel
    }

    /// Default zero levels.
    public static let zero = Self()
}

/// Real-time diagnostics for debugging the capture pipeline.
public struct CaptureSessionDiagnostics: Sendable {
    /// Number of mic audio callbacks received.
    public var micCallbackCount = 0
    /// Number of system audio callbacks received.
    public var systemCallbackCount = 0
    /// Total mic samples written to buffer.
    public var micSamplesTotal = 0
    /// Total system samples written to buffer (interleaved stereo count).
    public var systemSamplesTotal = 0
    /// Format description of last mic buffer received.
    public var micFormat = "—"
    /// Format description of last system buffer received.
    public var systemFormat = "—"
    /// Total bytes written to file.
    public var bytesWritten = 0
    /// Number of processBuffers cycles that produced output.
    public var mixCycles = 0

    public init() {}
}

import Foundation

/// Configuration for an audio capture session.
public struct CaptureConfiguration: Sendable {
    /// Audio sample rate in Hz. Default is 48000.
    public let sampleRate: Double

    /// Bit depth for audio samples. Default is 16.
    public let bitDepth: Int

    /// Number of audio channels. Default is 2 (stereo).
    public let channels: Int

    /// Optional encryptor for encrypting audio data at rest.
    public let encryptor: (any CaptureEncryptor)?

    /// Directory where recorded files will be stored.
    public let outputDirectory: URL

    /// Optional maximum recording duration in seconds.
    public let maxDuration: TimeInterval?

    /// Optional specific microphone device ID to use instead of the system default.
    public let micDeviceID: String?

    /// Whether to capture microphone audio. Default is true.
    public let enableMicCapture: Bool

    /// Whether to capture system audio. Default is true.
    public let enableSystemCapture: Bool

    public init(
        sampleRate: Double = 48000,
        bitDepth: Int = 16,
        channels: Int = 2,
        encryptor: (any CaptureEncryptor)? = nil,
        outputDirectory: URL,
        maxDuration: TimeInterval? = nil,
        micDeviceID: String? = nil,
        enableMicCapture: Bool = true,
        enableSystemCapture: Bool = true
    ) {
        self.sampleRate = sampleRate
        self.bitDepth = bitDepth
        self.channels = channels
        self.encryptor = encryptor
        self.outputDirectory = outputDirectory
        self.maxDuration = maxDuration
        self.micDeviceID = micDeviceID
        self.enableMicCapture = enableMicCapture
        self.enableSystemCapture = enableSystemCapture
    }
}

import Foundation

/// The result of a completed recording session.
public struct RecordingResult: Sendable, Equatable {
    /// URL of the recorded audio file on disk.
    public let fileURL: URL

    /// Total duration of the recording in seconds.
    public let duration: TimeInterval

    /// Associated metadata for the recording.
    public let metadata: RecordingMetadata

    /// SHA-256 checksum of the recorded file.
    public let checksum: String

    public init(fileURL: URL, duration: TimeInterval, metadata: RecordingMetadata, checksum: String) {
        self.fileURL = fileURL
        self.duration = duration
        self.metadata = metadata
        self.checksum = checksum
    }
}

import Foundation

/// Delegate protocol for receiving capture session events.
///
/// All delegate methods are called on an unspecified queue.
/// Implementations should dispatch to the main actor if UI updates are needed.
public protocol AudioCaptureDelegate: AnyObject, Sendable {
    /// Called when the capture session state changes.
    /// - Parameters:
    ///   - session: The capture session that changed state.
    ///   - state: The new state.
    func captureSession(_ session: any AudioCaptureSession, didChangeState state: CaptureState)

    /// Called periodically with updated audio level metering.
    /// - Parameters:
    ///   - session: The capture session providing levels.
    ///   - levels: The current audio levels.
    func captureSession(_ session: any AudioCaptureSession, didUpdateLevels levels: AudioLevels)

    /// Called when the capture session encounters a non-fatal error.
    /// - Parameters:
    ///   - session: The capture session that encountered the error.
    ///   - error: The error that occurred.
    func captureSession(_ session: any AudioCaptureSession, didEncounterError error: CaptureError)

    /// Called when the capture session finishes recording.
    /// - Parameters:
    ///   - session: The capture session that finished.
    ///   - result: The recording result containing file URL, duration, and metadata.
    func captureSession(_ session: any AudioCaptureSession, didFinishCapture result: RecordingResult)
}

