use std::path::PathBuf;

use super::super::traits::encryptor::CaptureEncryptor;

/// Configuration for a capture session.
///
/// Maps 1:1 to Swift `CaptureConfiguration`.
#[derive(Clone)]
pub struct CaptureConfiguration {
    /// Target sample rate in Hz (default: 48000).
    pub sample_rate: f64,

    /// Bit depth for PCM output (default: 16). Valid values: 16, 24, 32.
    pub bit_depth: u16,

    /// Number of output channels (default: 2 for stereo).
    pub channels: u16,

    /// Optional encryptor for streaming AES-256-GCM encryption.
    pub encryptor: Option<Box<dyn CaptureEncryptor>>,

    /// Directory where recording files are written.
    pub output_directory: PathBuf,

    /// Maximum recording duration in seconds (None = unlimited).
    pub max_duration_secs: Option<f64>,

    /// Specific microphone device ID, or None for system default.
    pub mic_device_id: Option<String>,

    /// Enable microphone capture (default: true).
    pub enable_mic_capture: bool,

    /// Enable system audio capture (default: true).
    pub enable_system_capture: bool,
}

impl CaptureConfiguration {
    pub fn validate(&self) -> Result<(), String> {
        if self.sample_rate <= 0.0 {
            return Err("sample rate must be positive".into());
        }
        if ![16, 24, 32].contains(&self.bit_depth) {
            return Err(format!("unsupported bit depth: {}", self.bit_depth));
        }
        if ![1, 2].contains(&self.channels) {
            return Err(format!("unsupported channel count: {}", self.channels));
        }
        Ok(())
    }
}

impl Default for CaptureConfiguration {
    fn default() -> Self {
        Self {
            sample_rate: 48000.0,
            bit_depth: 16,
            channels: 2,
            encryptor: None,
            output_directory: PathBuf::from("."),
            max_duration_secs: None,
            mic_device_id: None,
            enable_mic_capture: true,
            enable_system_capture: true,
        }
    }
}

use std::path::PathBuf;

use serde::{Deserialize, Serialize};

use super::audio_models::{AudioChannel, AudioTrack, AudioTrackType};

/// Result returned when a capture session completes successfully.
#[derive(Debug, Clone, PartialEq)]
pub struct RecordingResult {
    pub file_path: PathBuf,
    pub duration_secs: f64,
    pub metadata: RecordingMetadata,
    pub checksum: String,
}

/// Metadata stored alongside (or embedded in) a recording.
///
/// Serializable for JSON export to the backend.
#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
pub struct RecordingMetadata {
    pub id: String,
    pub duration_secs: f64,
    pub file_path: String,
    pub checksum: String,
    pub is_encrypted: bool,
    pub created_at: String,
    pub tracks: Vec<AudioTrack>,
    pub encryption_algorithm: Option<String>,
    pub encryption_key_id: Option<String>,
}

impl RecordingMetadata {
    /// Creates metadata for a standard mic + system stereo recording.
    pub fn new_stereo(
        duration_secs: f64,
        file_path: &str,
        checksum: &str,
        is_encrypted: bool,
        encryption_algorithm: Option<String>,
        encryption_key_id: Option<String>,
    ) -> Self {
        Self {
            id: uuid::Uuid::new_v4().to_string(),
            duration_secs,
            file_path: file_path.to_string(),
            checksum: checksum.to_string(),
            is_encrypted,
            created_at: chrono::Utc::now().to_rfc3339(),
            tracks: vec![
                AudioTrack {
                    track_type: AudioTrackType::Mic,
                    channel: AudioChannel::Center,
                },
                AudioTrack {
                    track_type: AudioTrackType::System,
                    channel: AudioChannel::Stereo,
                },
            ],
            encryption_algorithm,
            encryption_key_id,
        }
    }
}

