     1→use std::path::PathBuf;
     2→use std::sync::atomic::{AtomicBool, Ordering};
     3→use std::sync::Arc;
     4→use std::thread;
     5→use std::time::{Duration, Instant};
     6→
     7→use parking_lot::Mutex;
     8→
     9→use crate::models::audio_models::{AudioLevels, AudioSource, CaptureSessionDiagnostics};
    10→use crate::models::config::CaptureConfiguration;
    11→use crate::models::error::CaptureError;
    12→use crate::models::recording_result::{RecordingMetadata, RecordingResult};
    13→use crate::models::state::CaptureState;
    14→use crate::processing::ring_buffer::RingBuffer;
    15→use crate::processing::stereo_mixer::StereoMixer;
    16→use crate::processing::wav_format;
    17→use crate::storage::encrypted_writer::EncryptedFileWriter;
    18→use crate::traits::capture_delegate::CaptureDelegate;
    19→use crate::traits::capture_provider::CaptureProvider;
    20→
    21→/// Internal mutable session state, protected by `parking_lot::Mutex`.
    22→struct SessionState {
    23→    state: CaptureState,
    24→    levels: AudioLevels,
    25→    capture_start: Option<Instant>,
    26→    paused_duration: Duration,
    27→    last_pause_time: Option<Instant>,
    28→    diagnostics: CaptureSessionDiagnostics,
    29→    detected_mic_rate: Option<f64>,
    30→}
    31→
    32→impl SessionState {
    33→    fn new() -> Self {
    34→        Self {
    35→            state: CaptureState::Idle,
    36→            levels: AudioLevels::default(),
    37→            capture_start: None,
    38→            paused_duration: Duration::ZERO,
    39→            last_pause_time: None,
    40→            diagnostics: CaptureSessionDiagnostics::default(),
    41→            detected_mic_rate: None,
    42→        }
    43→    }
    44→
    45→    fn elapsed_duration(&self) -> f64 {
    46→        let Some(start) = self.capture_start else {
    47→            return 0.0;
    48→        };
    49→        let total = start.elapsed();
    50→        let active = total - self.paused_duration;
    51→        active.as_secs_f64()
    52→    }
    53→}
    54→
    55→/// Platform-agnostic capture session orchestrator.
    56→///
    57→/// Generic over mic and system audio backends via `CaptureProvider` trait.
    58→/// Handles mixing, buffering, encryption, and file output.
    59→///
    60→/// Ports Swift's `CompositeCaptureSession` with the same data flow:
    61→/// ```text
    62→/// [Mic Provider] → [Mic RingBuffer] ─┐
    63→///                                     ├→ [StereoMixer] → [PCM] → [EncryptedFileWriter]
    64→/// [System Provider] → [Sys RingBuffer]┘
    65→/// ```
    66→pub struct CompositeSession<M: CaptureProvider, S: CaptureProvider> {
    67→    mic: M,
    68→    system: S,
    69→    mixer: StereoMixer,
    70→    config: Option<CaptureConfiguration>,
    71→    session_state: Arc<Mutex<SessionState>>,
    72→    delegate: Option<Arc<dyn CaptureDelegate>>,
    73→
    74→    // Ring buffers shared between capture callbacks and processing thread
    75→    mic_buffer: Arc<Mutex<RingBuffer>>,
    76→    system_buffer: Arc<Mutex<RingBuffer>>,
    77→
    78→    // File writer (accessed from processing thread)
    79→    writer: Arc<Mutex<Option<EncryptedFileWriter>>>,
    80→
    81→    // Processing thread control
    82→    processing_running: Arc<AtomicBool>,
    83→    processing_handle: Option<thread::JoinHandle<()>>,
    84→
    85→    // Duration timer thread control
    86→    timer_running: Arc<AtomicBool>,
    87→    timer_handle: Option<thread::JoinHandle<()>>,
    88→
    89→    // Output file path for result
    90→    file_path: Option<PathBuf>,
    91→}
    92→
    93→impl<M: CaptureProvider, S: CaptureProvider> CompositeSession<M, S> {
    94→    pub fn new(mic: M, system: S) -> Self {
    95→        Self {
    96→            mic,
    97→            system,
    98→            mixer: StereoMixer::new(48000.0),
    99→            config: None,
   100→            session_state: Arc::new(Mutex::new(SessionState::new())),
   101→            delegate: None,
   102→            mic_buffer: Arc::new(Mutex::new(RingBuffer::new(1))), // placeholder, resized on configure
   103→            system_buffer: Arc::new(Mutex::new(RingBuffer::new(1))),
   104→            writer: Arc::new(Mutex::new(None)),
   105→            processing_running: Arc::new(AtomicBool::new(false)),
   106→            processing_handle: None,
   107→            timer_running: Arc::new(AtomicBool::new(false)),
   108→            timer_handle: None,
   109→            file_path: None,
   110→        }
   111→    }
   112→
   113→    pub fn set_delegate(&mut self, delegate: Arc<dyn CaptureDelegate>) {
   114→        self.delegate = Some(delegate);
   115→    }
   116→
   117→    pub fn state(&self) -> CaptureState {
   118→        self.session_state.lock().state.clone()
   119→    }
   120→
   121→    pub fn current_levels(&self) -> AudioLevels {
   122→        self.session_state.lock().levels
   123→    }
   124→
   125→    pub fn diagnostics(&self) -> CaptureSessionDiagnostics {
   126→        self.session_state.lock().diagnostics.clone()
   127→    }
   128→
   129→    pub fn available_audio_sources(&self) -> Result<Vec<AudioSource>, CaptureError> {
   130→        let mut sources = Vec::new();
   131→        if self.mic.is_available() {
   132→            sources.push(self.mic.device_info());
   133→        }
   134→        if self.system.is_available() {
   135→            sources.push(self.system.device_info());
   136→        }
   137→        Ok(sources)
   138→    }
   139→
   140→    /// Apply configuration. Transitions: idle → configuring → ready.
   141→    pub fn configure(&mut self, config: CaptureConfiguration) -> Result<(), CaptureError> {
   142→        {
   143→            let state = &self.session_state.lock().state;
   144→            if !state.is_idle() {
   145→                return Err(CaptureError::ConfigurationFailed(
   146→                    "can only configure from idle state".into(),
   147→                ));
   148→            }
   149→        }
   150→
   151→        config.validate().map_err(CaptureError::ConfigurationFailed)?;
   152→
   153→        self.set_state(CaptureState::Configuring);
   154→
   155→        self.mixer = StereoMixer::new(config.sample_rate);
   156→
   157→        // Size ring buffers for 5 seconds of audio
   158→        let buffer_capacity = (config.sample_rate * 5.0) as usize;
   159→        self.mic_buffer = Arc::new(Mutex::new(RingBuffer::new(buffer_capacity)));
   160→        self.system_buffer = Arc::new(Mutex::new(RingBuffer::new(buffer_capacity * 2))); // stereo
   161→
   162→        self.config = Some(config);
   163→        self.set_state(CaptureState::Ready);
   164→        Ok(())
   165→    }
   166→
   167→    /// Start capture. Transitions: ready → capturing.
   168→    pub fn start_capture(&mut self) -> Result<(), CaptureError> {
   169→        let config = self
   170→            .config
   171→            .as_ref()
   172→            .ok_or(CaptureError::ConfigurationFailed("not configured".into()))?;
   173→
   174→        {
   175→            let state = &self.session_state.lock().state;
   176→            if !matches!(state, CaptureState::Ready) {
   177→                return Err(CaptureError::ConfigurationFailed(
   178→                    "can only start from ready state".into(),
   179→                ));
   180→            }
   181→        }
   182→
   183→        let output_rate = config.sample_rate;
   184→
   185→        // Set up file writer
   186→        let file_name = format!("recording_{}", uuid::Uuid::new_v4());
   187→        let file_ext = if config.encryptor.is_some() { "enc.wav" } else { "wav" };
   188→        let file_path = config.output_directory.join(format!("{}.{}", file_name, file_ext));
   189→        self.file_path = Some(file_path.clone());
   190→
   191→        let mut writer = EncryptedFileWriter::new(file_path, config.encryptor.clone());
   192→        writer.open(config)?;
   193→        *self.writer.lock() = Some(writer);
   194→
   195→        // Start mic capture
   196→        if config.enable_mic_capture && self.mic.is_available() {
   197→            let mic_buf = Arc::clone(&self.mic_buffer);
   198→            let state = Arc::clone(&self.session_state);
   199→            let mixer = self.mixer.clone();
   200→
   201→            let callback = Arc::new(move |samples: &[f32], sample_rate: f64, channels: u16| {
   202→                // Downmix to mono if needed
   203→                let mono = if channels > 1 {
   204→                    wav_format::downmix_to_mono(samples, channels as usize)
   205→                } else {
   206→                    samples.to_vec()
   207→                };
   208→
   209→                // Resample to output rate
   210→                let resampled = mixer.resample(&mono, sample_rate);
   211→
   212→                // Update levels
   213→                let rms = StereoMixer::rms_level(&resampled);
   214→                let peak = StereoMixer::peak_level(&resampled);
   215→                {
   216→                    let mut s = state.lock();
   217→                    s.levels.mic_level = rms;
   218→                    s.levels.peak_mic_level = peak;
   219→                    s.diagnostics.mic_callback_count += 1;
   220→                    s.diagnostics.mic_samples_total += resampled.len() as u64;
   221→                }
   222→
   223→                // Write to ring buffer
   224→                mic_buf.lock().write(&resampled);
   225→            });
   226→
   227→            self.mic.start(callback)?;
   228→        }
   229→
   230→        // Start system audio capture
   231→        if config.enable_system_capture && self.system.is_available() {
   232→            let sys_buf = Arc::clone(&self.system_buffer);
   233→            let state = Arc::clone(&self.session_state);
   234→            let mixer = self.mixer.clone();
   235→
   236→            let callback = Arc::new(move |samples: &[f32], sample_rate: f64, channels: u16| {
   237→                // Resample stereo or mono→stereo
   238→                let resampled = if channels >= 2 {
   239→                    mixer.resample_stereo(samples, sample_rate)
   240→                } else {
   241→                    let mono = mixer.resample(samples, sample_rate);
   242→                    mixer.interleave(&mono, &mono)
   243→                };
   244→
   245→                // Update levels (use left channel for RMS)
   246→                let left_samples: Vec<f32> = resampled.iter().step_by(2).copied().collect();
   247→                let rms = StereoMixer::rms_level(&left_samples);
   248→                let peak = StereoMixer::peak_level(&left_samples);
   249→                {
   250→                    let mut s = state.lock();
   251→                    s.levels.system_level = rms;
   252→                    s.levels.peak_system_level = peak;
   253→                    s.diagnostics.system_callback_count += 1;
   254→                    s.diagnostics.system_samples_total += resampled.len() as u64;
   255→                }
   256→
   257→                // Write to ring buffer (stereo interleaved)
   258→                sys_buf.lock().write(&resampled);
   259→            });
   260→
   261→            self.system.start(callback)?;
   262→        }
   263→
   264→        // Mark capturing
   265→        {
   266→            let mut s = self.session_state.lock();
   267→            s.capture_start = Some(Instant::now());
   268→            s.paused_duration = Duration::ZERO;
   269→        }
   270→        self.set_state(CaptureState::Capturing { duration_secs: 0.0 });
   271→
   272→        // Start processing loop (100ms intervals)
   273→        self.start_processing_loop(output_rate);
   274→
   275→        // Start duration timer (250ms intervals)
   276→        self.start_duration_timer();
   277→
   278→        Ok(())
   279→    }
   280→
   281→    /// Pause capture. Transitions: capturing → paused.
   282→    pub fn pause_capture(&mut self) -> Result<(), CaptureError> {
   283→        let duration = {
   284→            let s = self.session_state.lock();
   285→            match &s.state {
   286→                CaptureState::Capturing { duration_secs } => *duration_secs,
